function App() {
  const { data, send } = useNodeRed();
  const mountRef = useRef(null);
  const sceneRef = useRef(null);
  const meshRef = useRef(null);
  const speedRef = useRef(1);
  const params = data || { rotSpeed: 1, color: '#22d3ee', scale: 1, shape: 'box' };

  useEffect(() => {
    speedRef.current = params.rotSpeed;
  }, [params.rotSpeed]);

  useEffect(() => {
    const THREE = require('three');
    const el = mountRef.current;
    const w = el.clientWidth;
    const h = el.clientHeight;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(50, w / h, 0.1, 100);
    camera.position.z = 4;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(window.devicePixelRatio);
    el.appendChild(renderer.domElement);

    const ambient = new THREE.AmbientLight(0xffffff, 0.4);
    scene.add(ambient);
    const point = new THREE.PointLight(0xffffff, 1.2, 100);
    point.position.set(5, 5, 5);
    scene.add(point);

    const geo = new THREE.TorusKnotGeometry(1, 0.35, 100, 16);
    const mat = new THREE.MeshStandardMaterial({ color: 0x22d3ee, roughness: 0.3, metalness: 0.7 });
    const mesh = new THREE.Mesh(geo, mat);
    scene.add(mesh);
    meshRef.current = mesh;
    sceneRef.current = { scene, camera, renderer, THREE };

    let raf;
    function animate() {
      raf = requestAnimationFrame(animate);
      mesh.rotation.x += 0.005 * speedRef.current;
      mesh.rotation.y += 0.01 * speedRef.current;
      renderer.render(scene, camera);
    }
    animate();

    const onResize = () => {
      const w2 = el.clientWidth;
      const h2 = el.clientHeight;
      camera.aspect = w2 / h2;
      camera.updateProjectionMatrix();
      renderer.setSize(w2, h2);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      geo.dispose();
      mat.dispose();
      el.removeChild(renderer.domElement);
    };
  }, []);

  useEffect(() => {
    if (!meshRef.current || !sceneRef.current) return;
    const { THREE } = sceneRef.current;
    const mesh = meshRef.current;
    const scene = sceneRef.current.scene;

    mesh.material.color.set(params.color);
    mesh.scale.setScalar(params.scale);

    const geoMap = {
      box: () => new THREE.BoxGeometry(1.4, 1.4, 1.4),
      sphere: () => new THREE.SphereGeometry(1, 32, 32),
      torus: () => new THREE.TorusGeometry(1, 0.4, 16, 48),
      knot: () => new THREE.TorusKnotGeometry(1, 0.35, 100, 16)
    };
    const makeFn = geoMap[params.shape] || geoMap.knot;
    const oldGeo = mesh.geometry;
    mesh.geometry = makeFn();
    oldGeo.dispose();
  }, [params.color, params.scale, params.shape]);

  const shapes = ['box', 'sphere', 'torus', 'knot'];

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col">
      <div className="flex items-center justify-between px-6 py-4">
        <div>
          <h1 className="text-xl font-semibold text-zinc-100 tracking-tight">fromcubes 3D</h1>
          <p className="text-xs text-zinc-600 mt-0.5">Three.js + live Node-RED data</p>
        </div>
        <div className="flex items-center gap-2">
          <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
          <span className="text-xs text-zinc-500">streaming</span>
        </div>
      </div>

      <div ref={mountRef} className="flex-1" />

      <div className="px-6 py-4 bg-zinc-900/50 border-t border-zinc-800/50 flex items-center gap-6 flex-wrap">
        <div className="flex gap-2">
          {shapes.map(s => (
            <button
              key={s}
              onClick={() => send({ shape: s })}
              className={`px-3 py-1.5 rounded-md text-xs transition-colors ${
                params.shape === s
                  ? 'bg-cyan-600 text-white'
                  : 'bg-zinc-800 text-zinc-400 hover:text-zinc-200'
              }`}
            >{s}</button>
          ))}
        </div>
        <div className="flex items-center gap-3">
          <span className="text-xs text-zinc-500">Speed</span>
          <span className="text-sm font-mono text-cyan-400">{params.rotSpeed}x</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-xs text-zinc-500">Scale</span>
          <span className="text-sm font-mono text-cyan-400">{params.scale}x</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-xs text-zinc-500">Color</span>
          <span className="w-4 h-4 rounded-full border border-zinc-700" style={{backgroundColor: params.color}} />
        </div>
      </div>
    </div>
  );
}
